import{_ as t,o as a,c as n,a0 as o}from"./chunks/framework.CWk8AOcY.js";const p=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"en/changelog.md","filePath":"changelog.md"}'),i={name:"en/changelog.md"};function r(s,e,l,d,c,u){return a(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><h2 id="_2026-04-27-release-v0-1-2" tabindex="-1">2026.04.27 Release v0.1.2 <a class="header-anchor" href="#_2026-04-27-release-v0-1-2" aria-label="Permalink to &quot;2026.04.27 Release v0.1.2&quot;">​</a></h2><h3 id="🛠️-critical-fixes" tabindex="-1">🛠️ Critical Fixes <a class="header-anchor" href="#🛠️-critical-fixes" aria-label="Permalink to &quot;🛠️ Critical Fixes&quot;">​</a></h3><ul><li><strong>Fixed</strong> the issue where CubeMaster returned a 5xx error instead of a 4xx error when the sandbox template does not exist.</li><li><strong>Fixed</strong> the missing SSL RootCA certificate issue during one-click deployment in v0.1.1.</li><li><strong>Fixed</strong> the cube proxy image build failure during deployment in v0.1.1.</li></ul><h2 id="_2026-04-24-release-v0-1-1" tabindex="-1">2026.04.24 Release v0.1.1 <a class="header-anchor" href="#_2026-04-24-release-v0-1-1" aria-label="Permalink to &quot;2026.04.24 Release v0.1.1&quot;">​</a></h2><h3 id="🛠️-critical-fixes-1" tabindex="-1">🛠️ Critical Fixes <a class="header-anchor" href="#🛠️-critical-fixes-1" aria-label="Permalink to &quot;🛠️ Critical Fixes&quot;">​</a></h3><ul><li><strong>Fixed</strong> the issue where the latest vmlinux was not used during template reconstruction, improving the stability of the sandbox environment.</li><li><strong>Updated</strong> the one-click installation script to support non-eth0 network interfaces, resolving stability issues with CubeProxy CA certificates.</li><li><strong>Disabled</strong> GRO on the primary network interface during initialization to enhance network stability.</li><li><strong>Fixed</strong> incorrect error handling when the target was not found during template cleanup, ensuring proper error returns.</li></ul><h3 id="✨-new-features" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features" aria-label="Permalink to &quot;✨ New Features&quot;">​</a></h3><ul><li><strong>Added</strong> the <code>cubebox destroy</code> command, enabling sandbox deletion via the CLI.</li><li><strong>Added</strong> integration examples for the OpenAI Agents SDK (including a code interpreter).</li></ul><h3 id="📚-documentation-updates" tabindex="-1">📚 Documentation Updates <a class="header-anchor" href="#📚-documentation-updates" aria-label="Permalink to &quot;📚 Documentation Updates&quot;">​</a></h3><ul><li><strong>Rewrote</strong> the HTTPS and domain configuration documentation, adding explanations for wildcard DNS records.</li></ul><h3 id="⚙️-engineering-improvements" tabindex="-1">⚙️ Engineering Improvements <a class="header-anchor" href="#⚙️-engineering-improvements" aria-label="Permalink to &quot;⚙️ Engineering Improvements&quot;">​</a></h3><ul><li><strong>Implemented</strong> a parallel CI build pipeline for multiple components to optimize build efficiency.</li><li><strong>Added</strong> support for automatic synchronization of GitHub Release assets to <code>cnb.cool/CubeSandbox/CubeSandbox</code>.</li></ul><h2 id="_2026-04-20-release-v0-1-0" tabindex="-1">2026.04.20 Release v0.1.0 <a class="header-anchor" href="#_2026-04-20-release-v0-1-0" aria-label="Permalink to &quot;2026.04.20 Release v0.1.0&quot;">​</a></h2><h3 id="initial-open-source-release-of-cube-sandbox" tabindex="-1">Initial open-source release of Cube Sandbox <a class="header-anchor" href="#initial-open-source-release-of-cube-sandbox" aria-label="Permalink to &quot;Initial open-source release of Cube Sandbox&quot;">​</a></h3><p><strong>Instant, Concurrent, Secure &amp; Lightweight Sandbox for AI Agents.</strong></p><h3 id="core-highlights" tabindex="-1">Core Highlights <a class="header-anchor" href="#core-highlights" aria-label="Permalink to &quot;Core Highlights&quot;">​</a></h3><p>Cube Sandbox is a high-performance, out-of-the-box secure sandbox service built on RustVMM and KVM. It supports both single-node deployment and can be easily scaled to a multi-node cluster. It is compatible with the E2B SDK, capable of creating a hardware-isolated sandbox environment with full service capabilities in under 60ms, while maintaining less than 5MB memory overhead.</p><ul><li><p>Blazing-fast cold start: built on resource pool pre-provisioning and snapshot cloning technology, average end-to-end cold start time for a fully serviceable sandbox is &lt; 60ms.</p></li><li><p>High-density deployment on a single node: extreme memory reuse via CoW technology combined with a Rust-rebuilt, aggressively trimmed runtime keeps per-instance memory overhead below 5MB — run thousands of Agents on a single machine.</p></li><li><p>True kernel-level isolation: each Agent runs with its own dedicated Guest OS kernel, eliminating container escape risks and enabling safe execution of any LLM-generated code.</p></li><li><p>Zero-cost migration (E2B drop-in replacement): natively compatible with the E2B SDK interface. Just swap one URL environment variable — no business logic changes needed.</p></li><li><p>Network security: CubeVS, powered by eBPF, enforces strict inter-sandbox network isolation at the kernel level with fine-grained egress traffic filtering policies.</p></li></ul><h3 id="production-ready" tabindex="-1">Production-ready <a class="header-anchor" href="#production-ready" aria-label="Permalink to &quot;Production-ready&quot;">​</a></h3><p><strong>Cube Sandbox has been validated at scale in Tencent Cloud production environments, proven stable and reliable</strong> — before this day it ever existed as open source, it had already quietly run behind real AI Agent workloads, serving real users, at production load.</p><p>In real production deployments, a single physical machine can spin up tens of thousands of sandboxes within minutes.</p><p>We open-source it today not as a prototype, but as production-hardened infrastructure that has already stood the test of real-world scale.</p><h3 id="a-note-to-every-contributor-—-past-present-and-future" tabindex="-1">A Note to Every Contributor — Past, Present, and Future <a class="header-anchor" href="#a-note-to-every-contributor-—-past-present-and-future" aria-label="Permalink to &quot;A Note to Every Contributor — Past, Present, and Future&quot;">​</a></h3><p>Before this code was ever public, it was already doing its job: spinning up sandboxes in milliseconds, isolating Agent workloads at the kernel level, and holding up under real production load at Tencent Cloud. None of that happened by accident.</p><p>Today we open the door. The high-performance Agent infrastructure you shaped now belongs to the world — to every developer who believes that safe, instant, and lightweight code execution should be open and self-hostable.</p><p>To those who contributed before this day: you built the foundation. To those who will contribute after: you are what turns a foundation into an ecosystem.</p><p>Open source shines because of you!</p>',28)])])}const g=t(i,[["render",r]]);export{p as __pageData,g as default};
